export const site_pages = pgTable(
  "site_pages",
  {
    id: serial("id").primaryKey(),
    title: varchar("title").notNull(),
    slug: varchar("slug").notNull(),
    presetKey: enum_site_pages_preset_key("preset_key").default("custom"),
    presetContent: jsonb("preset_content").default(sql`'{}'::jsonb`),
    isActive: boolean("is_active").default(false),
    hideNavbar: boolean("hide_navbar").default(false),
    hideFooter: boolean("hide_footer").default(false),
    pageBackgroundColor: varchar("page_background_color"),
    customHeadScripts: varchar("custom_head_scripts"),
    publishQualityScore: numeric("publish_quality_score", {
      mode: "number",
    }).default(100),
    publishQualityLevel: enum_site_pages_publish_quality_level(
      "publish_quality_level",
    ).default("excellent"),
    previewDiffSummary: jsonb("preview_diff_summary"),
    createdBy: integer("created_by_id").references(() => users.id, {
      onDelete: "set null",
    }),
    workflowStatus:
      enum_site_pages_workflow_status("workflow_status").default("draft"),
    submittedBy: integer("submitted_by_id").references(() => users.id, {
      onDelete: "set null",
    }),
    submittedAt: timestamp("submitted_at", {
      mode: "string",
      withTimezone: true,
      precision: 3,
    }),
    reviewChecklistComplete: boolean("review_checklist_complete").default(
      false,
    ),
    reviewSummary: varchar("review_summary"),
    approvedBy: integer("approved_by_id").references(() => users.id, {
      onDelete: "set null",
    }),
    approvedAt: timestamp("approved_at", {
      mode: "string",
      withTimezone: true,
      precision: 3,
    }),
    rejectionReason: varchar("rejection_reason"),
    seo_metaTitle: varchar("seo_meta_title"),
    seo_metaDescription: varchar("seo_meta_description"),
    seo_ogTitle: varchar("seo_og_title"),
    seo_ogDescription: varchar("seo_og_description"),
    seo_ogImage: integer("seo_og_image_id").references(() => media.id, {
      onDelete: "set null",
    }),
    seo_canonicalUrl: varchar("seo_canonical_url"),
    seo_noindex: boolean("seo_noindex").default(false),
    seo_nofollow: boolean("seo_nofollow").default(false),
    seo_includeInSitemap: boolean("seo_include_in_sitemap").default(true),
    meta_title: varchar("meta_title"),
    meta_description: varchar("meta_description"),
    meta_image: integer("meta_image_id").references(() => media.id, {
      onDelete: "set null",
    }),
    parent: integer("parent_id").references((): AnyPgColumn => site_pages.id, {
      onDelete: "set null",
    }),
    updatedAt: timestamp("updated_at", {
      mode: "string",
      withTimezone: true,
      precision: 3,
    })
      .defaultNow()
      .notNull(),
    createdAt: timestamp("created_at", {
      mode: "string",
      withTimezone: true,
      precision: 3,
    })
      .defaultNow()
      .notNull(),
    deletedAt: timestamp("deleted_at", {
      mode: "string",
      withTimezone: true,
      precision: 3,
    }),
  },
  (columns) => [
    uniqueIndex("site_pages_slug_idx").on(columns.slug),
    index("site_pages_created_by_idx").on(columns.createdBy),
    index("site_pages_submitted_by_idx").on(columns.submittedBy),
    index("site_pages_approved_by_idx").on(columns.approvedBy),
    index("site_pages_seo_seo_og_image_idx").on(columns.seo_ogImage),
    index("site_pages_meta_meta_image_idx").on(columns.meta_image),
    index("site_pages_parent_idx").on(columns.parent),
    index("site_pages_updated_at_idx").on(columns.updatedAt),
    index("site_pages_created_at_idx").on(columns.createdAt),
    index("site_pages_deleted_at_idx").on(columns.deletedAt),
  ],
);

